/// <reference path="../pb_data/types.d.ts" />

// Per-IP rate limit store: { [ip]: [timestamp_ms, ...] }
const rateLimitStore = {};

// Configuration
const MAX_REQUESTS = 3;
const WINDOW_SECONDS = 60;

/**
 * Clean up expired entries for a given IP and return the count of
 * remaining entries within the current window.
 */
function countAndClean(ip) {
    const now = Date.now();
    const windowMs = WINDOW_SECONDS * 1000;
    const cutoff = now - windowMs;

    let entries = rateLimitStore[ip];
    if (!entries) {
        return 0;
    }

    // Filter out timestamps older than the window
    entries = entries.filter(function(ts) {
        return ts > cutoff;
    });
    rateLimitStore[ip] = entries;

    return entries.length;
}

/**
 * Record a request for the given IP.
 */
function recordRequest(ip) {
    const now = Date.now();
    if (!rateLimitStore[ip]) {
        rateLimitStore[ip] = [];
    }
    rateLimitStore[ip].push(now);
}

onRecordCreateRequest(function(e) {
    const ip = e.realIP();
    const count = countAndClean(ip);

    if (count >= MAX_REQUESTS) {
        // Calculate how many seconds until the oldest entry in the window expires
        const now = Date.now();
        const windowMs = WINDOW_SECONDS * 1000;
        const oldest = rateLimitStore[ip][0];
        const elapsed = now - oldest;
        const remainingMs = windowMs - elapsed;
        const retryAfter = Math.max(1, Math.ceil(remainingMs / 1000));

        // Set Retry-After header
        e.response.header().set("Retry-After", String(retryAfter));

        throw new TooManyRequestsError(
            "Too many signup attempts. Please try again later.",
            { "retryAfter": retryAfter }
        );
    }

    // Record this request before proceeding
    recordRequest(ip);

    return e.next();
}, "users");
